 7	import { buildBookChapterJsonLd, serializeJsonLd } from '@/lib/json-ld';
 8	import { getBookUrl, getBookChapterUrl } from '@/lib/urls';
 9	
10	export async function generateStaticParams() {
11	  const books = getAllBooks();
12	  if (books.length === 0) return [{ slug: '_', chapter: '_' }];
13	  const params: { slug: string; chapter: string }[] = [];
14	
15	  for (const book of books) {
16	    for (const ch of book.chapters) {
17	      // Only include chapters whose files exist and parse successfully.
18	      // A chapter listed in index.mdx but not yet written (or with invalid
19	      // frontmatter) would cause notFound() at render time, which in
20	      // output:export dev mode surfaces as a confusing "missing param" 500.
